#include<bits/stdc++.h>
using namespace std;
typedef unsigned long long u64;


const u64 MOD1 = 1e9 + 7;
const u64 MOD2 = 1e9 + 9;
const u64 BASE = 13331;

pair<u64, u64> get_Hash(string s)
{
    u64 h1 = 0, h2 = 0;
    for(int i = 0; i < s.size(); ++i){
        h1 = (h1 * BASE + s[i]) % MOD1;
        h2 = (h2 * BASE + s[i]) % MOD2;
    }
    return make_pair(h1, h2);
}

int main()
{
    int n;
    cin >> n;
    vector<pair<u64, u64> > v;
    for(int i = 1; i <= n; i++){
        string s;
        cin >> s;
        auto h = get_Hash(s);
        v.push_back(h);
    }
    sort(v.begin(), v.end());
    cout << unique(v.begin(), v.end()) - v.begin() << endl;
}
